document.addEventListener("DOMContentLoaded",(function(){document.querySelectorAll(".topppa-trip-gallery-slider").forEach((function(e){e.classList.contains("swiper-initialized")||new Swiper(e,{slidesPerView:1,loop:!0,speed:600,nested:!0,grabCursor:!0,watchSlidesProgress:!0,pagination:{el:".trip-destination-gallery-pagination",clickable:!0}})}))})),document.addEventListener("DOMContentLoaded",(()=>{if("undefined"==typeof gsap)return;gsap.registerPlugin(ScrollTrigger);const e=document.querySelector(".no-slide");if(!e)return;const t=e.querySelectorAll(".topppa-trip-item");t.length&&gsap.from(t,{scrollTrigger:{trigger:e,start:"top 80%"},opacity:0,y:40,scale:.9,duration:.5,ease:"power3.out",stagger:.1,clearProps:"all"})}));